import { faker } from '@faker-js/faker';

// Generate mock metrics data
export const generateMetricsData = () => {
  const now = new Date();
  const days = 30;
  const data = [];
  
  for (let i = days; i >= 0; i--) {
    const date = new Date(now);
    date.setDate(date.getDate() - i);
    
    data.push({
      date: date.toISOString().split('T')[0],
      revenue: faker.number.int({ min: 5000, max: 25000 }),
      payments: faker.number.int({ min: 50, max: 200 }),
      customers: faker.number.int({ min: 10, max: 50 }),
      disputes: faker.number.int({ min: 0, max: 5 })
    });
  }
  
  return data;
};

// Generate mock payment data
export const generatePayments = (count = 50) => {
  return Array.from({ length: count }, () => ({
    id: faker.string.alphanumeric(8).toUpperCase(),
    customer: faker.person.fullName(),
    email: faker.internet.email(),
    amount: faker.number.int({ min: 500, max: 50000 }) / 100,
    currency: faker.helpers.arrayElement(['usd', 'eur', 'gbp']),
    status: faker.helpers.arrayElement(['succeeded', 'pending', 'failed']),
    created: faker.date.recent({ days: 30 }),
    description: faker.commerce.productName(),
    method: faker.helpers.arrayElement(['card', 'bank_transfer', 'wallet'])
  }));
};

// Generate mock customer data
export const generateCustomers = (count = 100) => {
  return Array.from({ length: count }, () => ({
    id: faker.string.uuid(),
    name: faker.person.fullName(),
    email: faker.internet.email(),
    created: faker.date.past({ years: 2 }),
    totalSpent: faker.number.int({ min: 100, max: 10000 }) / 100,
    paymentsCount: faker.number.int({ min: 1, max: 50 }),
    country: faker.location.country(),
    status: faker.helpers.arrayElement(['active', 'inactive'])
  }));
};

// Generate summary statistics
export const generateSummaryStats = () => {
  const payments = generatePayments(1000);
  const totalRevenue = payments.reduce((sum, payment) => 
    payment.status === 'succeeded' ? sum + payment.amount : sum, 0
  );
  const successfulPayments = payments.filter(p => p.status === 'succeeded').length;
  const failedPayments = payments.filter(p => p.status === 'failed').length;
  
  return {
    totalRevenue,
    successfulPayments,
    failedPayments,
    totalCustomers: faker.number.int({ min: 500, max: 2000 }),
    activeCustomers: faker.number.int({ min: 300, max: 1500 }),
    disputeRate: faker.number.float({ min: 0.1, max: 2.5, precision: 0.1 }),
    avgOrderValue: totalRevenue / successfulPayments
  };
}; 