import React from 'react';
import { useLocation } from 'react-router-dom';
import styled from 'styled-components';

const HeaderContainer = styled.div`
  height: 60px;
  background: white;
  border-bottom: 1px solid #e6ebf1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 24px;
  position: sticky;
  top: 0;
  z-index: 999;
`;

const HeaderLeft = styled.div`
  display: flex;
  align-items: center;
`;

const PageTitle = styled.h1`
  font-size: 24px;
  font-weight: 500;
  color: #0a2540;
  margin: 0;
`;

const SearchBar = styled.div`
  display: flex;
  align-items: center;
  background: #f6f9fc;
  border-radius: 6px;
  padding: 8px 12px;
  margin-left: 24px;
  width: 300px;
  
  input {
    border: none;
    background: none;
    outline: none;
    width: 100%;
    font-size: 14px;
    color: #425466;
    
    &::placeholder {
      color: #8792a2;
    }
  }
`;

const HeaderRight = styled.div`
  display: flex;
  align-items: center;
  gap: 16px;
`;

const NotificationIcon = styled.div`
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: #f6f9fc;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.2s ease;
  
  &:hover {
    background: #e3e8ee;
  }
`;

const UserAvatar = styled.div`
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: #635bff;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-weight: 500;
  cursor: pointer;
`;

const Header = () => {
  const location = useLocation();
  
  const getPageTitle = () => {
    const path = location.pathname;
    if (path === '/') return 'Home';
    if (path.startsWith('/metrics')) return 'Metrics';
    if (path.startsWith('/billing')) return 'Billing';
    if (path.startsWith('/data')) return 'Data & Analytics';
    if (path.startsWith('/reports')) return 'Reports';
    return 'Dashboard';
  };
  
  return (
    <HeaderContainer>
      <HeaderLeft>
        <PageTitle>{getPageTitle()}</PageTitle>
        <SearchBar>
          <span style={{ marginRight: '8px', color: '#8792a2' }}>🔍</span>
          <input type="text" placeholder="Search customers, payments, products..." />
        </SearchBar>
      </HeaderLeft>
      
      <HeaderRight>
        <NotificationIcon>🔔</NotificationIcon>
        <UserAvatar>JD</UserAvatar>
      </HeaderRight>
    </HeaderContainer>
  );
};

export default Header; 