import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import styled from 'styled-components';

const SidebarContainer = styled.div`
  width: 64px;
  height: 100vh;
  background: #1a1f36;
  position: fixed;
  left: 0;
  top: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 16px 0;
  z-index: 1000;
`;

const Logo = styled.div`
  width: 32px;
  height: 32px;
  background: #635bff;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 32px;
  font-weight: bold;
  color: white;
  font-size: 18px;
`;

const NavIcon = styled(Link)`
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 8px;
  margin-bottom: 8px;
  text-decoration: none;
  color: #8792a2;
  font-size: 20px;
  transition: all 0.2s ease;
  
  &:hover {
    background: rgba(99, 91, 255, 0.1);
    color: #635bff;
  }
  
  ${props => props.$active && `
    background: rgba(99, 91, 255, 0.1);
    color: #635bff;
  `}
`;

const Sidebar = () => {
  const location = useLocation();
  
  const isActive = (path) => {
    if (path === '/' && location.pathname === '/') return true;
    if (path !== '/' && location.pathname.startsWith(path)) return true;
    return false;
  };
  
  return (
    <SidebarContainer>
      <Logo>S</Logo>
      <NavIcon to="/" $active={isActive('/')}>🏠</NavIcon>
      <NavIcon to="/metrics" $active={isActive('/metrics')}>📊</NavIcon>
      <NavIcon to="/billing" $active={isActive('/billing')}>💳</NavIcon>
      <NavIcon to="/data" $active={isActive('/data')}>📈</NavIcon>
      <NavIcon to="/reports" $active={isActive('/reports')}>📋</NavIcon>
    </SidebarContainer>
  );
};

export default Sidebar; 