import React, { useEffect } from 'react';
import { Routes, Route, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import Dashboard from './pages/Dashboard';
import Metrics from './pages/Metrics';
import Billing from './pages/Billing';
import Data from './pages/Data';
import Reports from './pages/Reports';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import './styles/App.css';
import styled from 'styled-components';

const MainContainer = styled.div`
  margin-left: 64px;
  width: calc(100% - 64px);
  height: 100vh;
  overflow-y: auto;
`;

const PageWrapper = styled(motion.div)`
  min-height: calc(100vh - 60px);
`;

// Component to handle document title updates
const DocumentTitle = () => {
  const location = useLocation();
  
  useEffect(() => {
    let pageTitle = "Stripe Dashboard";
    
    const path = location.pathname;
    
    if (path === "/") {
      pageTitle = "Home - Stripe Dashboard";
    } else if (path.startsWith("/metrics")) {
      pageTitle = "Metrics - Stripe Dashboard";
    } else if (path.startsWith("/billing")) {
      pageTitle = "Billing - Stripe Dashboard";
    } else if (path.startsWith("/data")) {
      pageTitle = "Data & Analytics - Stripe Dashboard";
    } else if (path.startsWith("/reports")) {
      pageTitle = "Reports - Stripe Dashboard";
    }
    
    document.title = pageTitle;
  }, [location]);
  
  return null;
};

const pageTransition = {
  initial: { opacity: 0, y: 20 },
  animate: { opacity: 1, y: 0 },
  exit: { opacity: 0, y: -20 },
  transition: { duration: 0.3, ease: "easeInOut" }
};

function App() {
  const location = useLocation();

  return (
    <div className="app">
      <DocumentTitle />
      <Sidebar />
      <MainContainer>
        <Header />
        <AnimatePresence mode="wait">
          <Routes location={location} key={location.pathname}>
            <Route 
              path="/" 
              element={
                <PageWrapper {...pageTransition}>
                  <Dashboard />
                </PageWrapper>
              } 
            />
            <Route 
              path="/metrics" 
              element={
                <PageWrapper {...pageTransition}>
                  <Metrics />
                </PageWrapper>
              } 
            />
            <Route 
              path="/billing" 
              element={
                <PageWrapper {...pageTransition}>
                  <Billing />
                </PageWrapper>
              } 
            />
            <Route 
              path="/data" 
              element={
                <PageWrapper {...pageTransition}>
                  <Data />
                </PageWrapper>
              } 
            />
            <Route 
              path="/reports" 
              element={
                <PageWrapper {...pageTransition}>
                  <Reports />
                </PageWrapper>
              } 
            />
            <Route 
              path="*" 
              element={
                <PageWrapper {...pageTransition}>
                  <Dashboard />
                </PageWrapper>
              } 
            />
          </Routes>
        </AnimatePresence>
      </MainContainer>
    </div>
  );
}

export default App;